DASHBOARD_HTML = '<!doctype html>\n<html>\n<head>\n  <meta charset=\'utf-8\'>\n  <title>Claire Internet Operations Dashboard</title>\n  <style>\n    body { font-family: Arial, sans-serif; margin: 24px; background: #0f172a; color: #e2e8f0; }\n    h1 { margin-bottom: 4px; }\n    .muted { color: #94a3b8; }\n    .grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 16px; margin-top: 20px; }\n    .card { background: #111827; border: 1px solid #334155; border-radius: 12px; padding: 16px; }\n    .healthy { color: #22c55e; }\n    .degraded, .warning { color: #f59e0b; }\n    .error { color: #ef4444; }\n    button { background: #2563eb; color: white; border: 0; border-radius: 8px; padding: 8px 12px; cursor: pointer; }\n    input { padding: 8px; border-radius: 8px; border: 1px solid #475569; background: #020617; color: #e2e8f0; }\n    pre { white-space: pre-wrap; background: #020617; border: 1px solid #334155; border-radius: 8px; padding: 12px; max-height: 420px; overflow: auto; }\n  </style>\n</head>\n<body>\n  <h1>Claire Internet Operations Dashboard</h1>\n  <div class=\'muted\'>Governed internet campaigns, scheduler health, runtime stability, and source trust.</div>\n  <p>\n    <button onclick=\'loadSnapshot()\'>Refresh Dashboard</button>\n    <button onclick=\'runDue()\'>Run Due Updates</button>\n    <input id=\'campaignId\' placeholder=\'campaign_id for manual refresh\'>\n    <button onclick=\'refreshCampaign()\'>Refresh Campaign</button>\n  </p>\n  <div id=\'summary\' class=\'grid\'></div>\n  <h2>Raw Snapshot</h2>\n  <pre id=\'raw\'>Loading...</pre>\n  <script>\n    async function loadSnapshot() {\n      const res = await fetch(\'/internet/ops/snapshot\');\n      render(await res.json());\n    }\n    async function runDue() {\n      const res = await fetch(\'/internet/ops/run-due\', { method: \'POST\' });\n      render(await res.json());\n    }\n    async function refreshCampaign() {\n      const id = document.getElementById(\'campaignId\').value.trim();\n      if (!id) { alert(\'Enter campaign_id\'); return; }\n      const res = await fetch(\'/internet/ops/campaigns/\' + encodeURIComponent(id) + \'/refresh\', { method: \'POST\' });\n      render(await res.json());\n    }\n    function render(data) {\n      document.getElementById(\'raw\').textContent = JSON.stringify(data, null, 2);\n      const summary = document.getElementById(\'summary\');\n      summary.innerHTML = \'\';\n      for (const panel of (data.panels || [])) {\n        const div = document.createElement(\'div\');\n        div.className = \'card\';\n        div.innerHTML = \'<h3>\' + panel.panel + \'</h3>\' +\n          \'<div>Status: <b class="\' + panel.status + \'">\' + panel.status + \'</b></div>\' +\n          \'<div>Count: \' + panel.count + \'</div>\';\n        summary.appendChild(div);\n      }\n      const recs = data.recommendations || [];\n      const rec = document.createElement(\'div\');\n      rec.className = \'card\';\n      rec.innerHTML = \'<h3>Recommendations</h3>\' + (recs.length ? \'<ul>\' + recs.map(r => \'<li>\' + r + \'</li>\').join(\'\') + \'</ul>\' : \'<div>No recommendations.</div>\');\n      summary.appendChild(rec);\n    }\n    loadSnapshot();\n  </script>\n</body>\n</html>\n'
